final class DeepLinkRouter {
    static let shared = DeepLinkRouter()

    var navigationControllerProvider: (() -> UINavigationController?)?

    private let allowedHosts: Set<String> = ["myapp.com", "www.myapp.com"]
    private let resetPasswordPathOptions: Set<String> = ["/reset-password", "/resetpassword", "/account/reset-password"]

    @discardableResult
    func handle(url: URL) -> Bool {
        guard let route = DeepLinkRoute(url: url, allowedHosts: allowedHosts, resetPasswordPathOptions: resetPasswordPathOptions) else {
            return false
