        DispatchQueue.main.async { [weak self] in
            self?.navigate(to: route)
        }
        return true
    }

    private func navigate(to route: DeepLinkRoute) {
        guard let nav = navigationControllerProvider?() else { return }

        switch route {
        case .resetPassword(let token):
            let vc = PasswordResetViewController(token: token)
            nav.popToRootViewController(animated: false)

            if let top = nav.topViewController as? PasswordResetViewController {
                top.updateToken(token)
            } else {
                nav.pushViewController(vc, animated: true)
            }
        }
    }
