enum DeepLinkRoute: Equatable {
    case resetPassword(token: String)

    init?(url: URL, allowedHosts: Set<String>, resetPasswordPathOptions: Set<String>) {
        guard var components = URLComponents(url: url, resolvingAgainstBaseURL: false) else { return nil }

        if components.scheme == nil {
            components.scheme = "https"
        }

        guard let host = components.host?.lowercased(),
              allowedHosts.contains(host)
        else { return nil }

        let path = components.path.lowercased()
        guard resetPasswordPathOptions.contains(path) else { return nil }

        let token = components.queryItems?.first(where: { $0.name.lowercased() == "token" })?.value ?? ""
        let trimmed = token.trimmingCharacters(in: .whitespacesAndNewlines)

        guard !trimmed.isEmpty else { return nil }

        self = .resetPassword(token: trimmed)
    }
}

