final class PasswordResetViewController: UIViewController {
    private var token: String

    private let tokenLabel = UILabel()
    private let passwordField = UITextField()
    private let confirmField = UITextField()
    private let resetButton = UIButton(type: .system)

    init(token: String) {
        self.token = token
        super.init(nibName: nil, bundle: nil)
    }

    required init?(coder: NSCoder) {
        fatalError("init(coder:) has not been implemented")
    }

    override func viewDidLoad() {
        super.viewDidLoad()
        title = "Reset Password"
        view.backgroundColor = .systemBackground
        setupUI()
        render()
    }

    func updateToken(_ token: String) {
        self.token = token
        if isViewLoaded { render() }
    }

    private func setupUI() {
        tokenLabel.numberOfLines = 0
        tokenLabel.font = .monospacedSystemFont(ofSize: 12, weight: .regular)
        tokenLabel.textColor = .secondaryLabel

        passwordField.placeholder = "New password"
        passwordField.isSecureTextEntry = true
        passwordField.borderStyle = .roundedRect
        passwordField.textContentType = .newPassword

        confirmField.placeholder = "Confirm new password"
        confirmField.isSecureTextEntry = true
        confirmField.borderStyle = .roundedRect
        confirmField.textContentType = .newPassword

        resetButton.setTitle("Reset Password", for: .normal)
        resetButton.addTarget(self, action: #selector(didTapReset), for: .touchUpInside)

        let stack = UIStackView(arrangedSubviews: [tokenLabel, passwordField, confirmField, resetButton])
        stack.translatesAutoresizingMaskIntoConstraints = false
        stack.axis = .vertical
        stack.spacing = 12

        view.addSubview(stack)

        NSLayoutConstraint.activate([
            stack.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 20),
            stack.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -20),
            stack.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor, constant: 20)
        ])
    }

    private func render() {
        tokenLabel.text = "Token:\n\(token)"
    }

    @objc private func didTapReset() {
        let newPassword = passwordField.text ?? ""
        let confirm = confirmField.text ?? ""

        guard !newPassword.isEmpty, newPassword == confirm else {
            let alert = UIAlertController(title: "Error",
                                          message: "Passwords must match and not be empty.",
                                          preferredStyle: .alert)
            alert.addAction(UIAlertAction(title: "OK", style: .default))
            present(alert, animated: true)
            return
        }

        let alert = UIAlertController(title: "Reset Requested",
                                      message: "Send token + new password to your backend.\n\nToken: \(token)",
                                      preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
}